mapper.select:
SELECT a.id AS artwork_id, a.artwork_no, a.artist_id, ap.artist_name, COALESCE(al.level_name, '签约艺术家') AS artist_level_name, a.title, a.category, a.sale_mode, a.status, ( SELECT am.media_url FROM artwork_media am WHERE am.artwork_id = a.id ORDER BY am.is_main DESC, am.sort_no ASC, am.id ASC LIMIT 1 ) AS cover_url, a.current_price, a.favorite_count, a.view_count, COALESCE(a.admin_weight, 1) AS admin_weight FROM artwork a INNER JOIN artist_profile ap ON ap.id = a.artist_id LEFT JOIN artist_level al ON al.id = ap.level_id
a.status = #{status}
AND a.category = #{category}
AND a.artist_id = #{artistId}
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR ap.artist_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY a.admin_weight DESC, a.created_at DESC
